import{_ as i}from"./ServicePage-BnMNeeNI.js";import{o as t,c as s,n as a,g as n}from"./index-BH5b9vWe.js";const p={__name:"Accessibility",setup(o){const e={title:"Accessibility & WCAG Compliance",subtitle:"WCAG violations are legal liability. They're also excluding 15-20% of potential customers.",problem:"Web accessibility isn't optional—it's increasingly a legal requirement. ADA lawsuits against websites have grown dramatically. Beyond legal risk, inaccessible sites exclude users with disabilities: that's 1 in 5 people. You're leaving money on the table and exposing yourself to lawsuits.",businessCase:"Web accessibility lawsuits exceeded 4,500 in 2023. Schools, healthcare, municipalities, and e-commerce are common targets. But even without legal pressure, the disability community represents $8 trillion in global spending power. Accessibility is good business.",symptoms:["No alt text on important images","Poor color contrast on text","Forms without proper labels","Can't navigate the site with keyboard only","No skip navigation links","Videos without captions"],whatWeDo:[{title:"WCAG 2.1 Audit",description:"We test against WCAG 2.1 AA guidelines—the standard for legal compliance. Automated scans plus manual testing with real assistive technology."},{title:"Priority Remediation",description:"We prioritize fixes by legal risk and user impact. Critical issues first, then systematic cleanup of remaining violations."},{title:"Keyboard Navigation",description:"We ensure your entire site works without a mouse. Focus states, tab order, skip links, and proper interactive element roles."},{title:"Accessible Components",description:"We rebuild inaccessible UI components: modals, dropdowns, carousels, forms. Native HTML where possible, ARIA where necessary."}],approach:[{title:"Design-to-Code Precision",description:"We communicate in design language—exact pixel values, gradient angles, specific rgba colors. We read from design specs and translate them accurately. Many devs approximate; we implement exactly."},{title:"Component-Based CSS Architecture",description:"Clean structure with dedicated partials per component, consistent BEM naming, and centralized variables. This scales well and makes handoffs easy. We write CSS that other devs can maintain."},{title:"Efficient Communication",description:"Terse, unambiguous instructions. No back-and-forth needed. We get it without endless clarification—saving everyone time."}],relatedServices:[{title:"Redesign",link:"/services/redesign"},{title:"Performance",link:"/services/performance"},{title:"Conversion",link:"/services/conversion"}]};return(r,l)=>(t(),s(i,a(n(e)),null,16))}};export{p as default};
